INSERT INTO Submission (query_text, subtype_id, emotion_id, concept_id, outcome_id, feedback_target) VALUES
  ('DELETE FROM Logs WHERE COUNT(*) < 10;', 1, 1, 10, 25, 'No stress! Note that you cannot use COUNT(*) in the WHERE clause of a DELETE statement. Aggregates must be used in a subquery with GROUP BY and HAVING.'),
  ('SELECT Division, COUNT(Employee_ID, Name) FROM Employees GROUP BY Division;', 1, 4, 2, 24, 'COUNT() does not accept multiple arguments.'),
  ('SELECT Employee_ID, MAX() FROM Robots GROUP BY Employee_ID;', 1, 3, 2, 23, 'Good Attempt! But MAX needs a column parameter.'),
  ('SELECT COUNT() FROM Robots WHERE Status = ''Inactive'';', 1, 2, 10, 24, 'Remember to specify the column you want to count. Use COUNT(Robot_ID) or COUNT(*) instead of just COUNT().'),
  ('SELECT e.Division, MAX(COUNT(r.Robot_ID)) FROM Employees e LEFT JOIN Robots r ON e.Employee_ID = r.Employee_ID GROUP BY e.Division;', 1, 4, 2, 27, 'You can''t nest aggregate functions like MAX(COUNT()).'),
  ('SELECT MAX(Employee_ID, Robot_ID) FROM Logs;', 1, 5, 7, 26, 'Don''t worry, it''s an easy mistake! MAX takes only one parameter.'),
  ('SELECT Employee_ID, COUNT() FROM Robots WHERE Status = ''Active'' GROUP BY Employee_ID;', 1, 2, 2, 24, 'Remember to specify the column inside the COUNT() function, like COUNT(Robot_ID).'),
  ('SELECT Employee_ID, MAX(AVG(Timestamp)) FROM Logs GROUP BY Employee_ID;', 1, 3, 2, 27, 'Good job on trying to nest aggregate functions! However, you can''t directly nest MAX and AVG. Try using a subquery or a derived table to achieve this.'),
  ('SELECT Robot_ID, COUNT(Incident_ID, Employee_ID) FROM Incidents GROUP BY Robot_ID;', 1, 1, 2, 24, 'Whoa, stay cool! COUNT can''t take multiple columns as arguments.'),
  ('SELECT Employee_ID, COUNT() AS Log_Count FROM Logs WHERE Action_Description = ''software update'' GROUP BY Employee_ID HAVING COUNT(Log_ID) > 5;', 1, 5, 2, 24, 'Don''t worry! You''re close. COUNT needs a parameter.'),
  ('SELECT Robot_ID, (SELECT MAX(*) FROM Logs l WHERE l.Robot_ID = r.Robot_ID) as last_log FROM Robots r;', 1, 1, 10, 26, 'Don''t worry! I''m here to help you! You cannot use MAX(*). Aggregate functions like MAX require a specific column name.'),
  ('SELECT MAX(Timestamp_of_Last_Use, Employee_ID) FROM Access_Codes;', 1, 2, 7, 26, 'MAX() does not accept multiple arguments. Use it with a single column.'),
  ('SELECT Job_Role, COUNT(*) FROM Employees GROUP BY Job_Role HAVING COUNT >= 1;', 1, 3, 2, 24, 'Great try! However, in the HAVING clause, you must use the full aggregate function.'),
  ('SELECT Employee_ID, MIN(MAX(Timestamp_of_Last_Use)) FROM Access_Codes GROUP BY Employee_ID;', 1, 4, 2, 27, 'You''re close! However, you can''t nest aggregate functions like MIN(MAX()).'),
  ('SELECT MIN(Robot_ID, Employee_ID) FROM Incidents;', 1, 5, 7, 26, 'Don''t worry, it''s an easy mistake! MIN takes only one parameter.'),
  ('SELECT Division, COUNT(*) FROM Employees WHERE COUNT(*) > 5 GROUP BY Division;', 1, 2, 2, 25, 'Aggregate functions like COUNT() cannot be used in the WHERE clause.'),
  ('SELECT Employee_ID, AVG() FROM Logs GROUP BY Employee_ID;', 1, 3, 2, 26, 'Great job with the GROUP BY! However, AVG needs a parameter.'),
  ('SELECT Robot_ID, COUNT(Employee_ID) FROM Logs GROUP BY Robot_ID HAVING COUNT() > 5;', 1, 4, 2, 24, 'Remember to specify the column inside the COUNT() function.'),
  ('SELECT Status, COUNT(Employee_ID, Model) FROM Robots GROUP BY Status;', 1, 4, 2, 24, 'COUNT() does not accept multiple columns.'),
  ('SELECT Robot_ID, COUNT(*) FROM Logs GROUP BY Robot_ID ORDER BY COUNT;', 1, 2, 2, 24, 'ORDER BY COUNT is invalid because COUNT is a function, not a column name.'),
  ('SELECT AVG FROM Robots WHERE Status = ''broken'';', 1, 5, 10, 26, 'Don''t worry! Remember that AVG without parentheses is just a keyword, not a function call. Always include () with the column you want to average.'),
  ('SELECT Job_Role FROM Employees GROUP BY Job_Role HAVING COUNT() > 1;', 1, 3, 2, 24, 'Great job on using HAVING! However, COUNT() cannot be empty. Use COUNT(*) or COUNT(column) inside the HAVING clause.'),
  ('SELECT Employee_ID, Description, COUNT(*) FROM Incidents GROUP BY Employee_ID, Description WHERE COUNT(*) > 1;', 1, 1, 2, 24, 'Take a deep breath! You''re trying to use COUNT(*) in the WHERE clause, which is not allowed. Instead, try using HAVING.'),
  ('UPDATE Robots SET Status = ''maintenance'' WHERE Employee_ID IN (SELECT Employee_ID FROM Logs WHERE COUNT(*) > 10);', 1, 3, 10, 25, 'Good Start! However, you cannot use COUNT(*) in a WHERE clause. Aggregate functions must be used with GROUP BY and HAVING.'),
  ('SELECT MIN(*) FROM Access_Codes;', 1, 2, 7, 26, 'Aggregate functions like MIN require a specific column name.'),
  ('SELECT Employee_ID, COUNT() FROM Robots GROUP BY Employee_ID HAVING COUNT() > 1;', 1, 5, 2, 24, 'Don''t worry, it''s an easy mistake! When using COUNT(), make sure to specify the column you want to count, like COUNT(Robot_ID). COUNT() without a column will throw an error.'),
  ('SELECT AVG(Robot_ID, Employee_ID) FROM Robots WHERE Model = ''X100'';', 1, 1, 10, 26, 'Take a deep breath! AVG() does not accept multiple columns. It must take a single numeric expression.'),
  ('SELECT Employee_ID, COUNT(Robot_ID) FROM Robots WHERE COUNT(Robot_ID) > 5 GROUP BY Employee_ID;', 1, 2, 2, 25, 'COUNT() cannot be used in the WHERE clause. Move it to the HAVING clause.'),
  ('SELECT SUM Employee_ID FROM Employees;', 1, 1, 7, 26, 'Stay calm! Remember SUM is an aggregate function that requires parentheses to enclose its parameter.'),
  ('SELECT COUNT FROM Access_Codes;', 1, 5, 7, 24, 'Don''t be discouraged! Add COUNT(*) to count all records or COUNT(Employee_ID) to count specific values.'),
  ('SELECT COUNT(Employee_ID, Name) FROM Employees;', 1, 5, 7, 24, 'Don''t worry about function parameters. Use separate COUNT functions: COUNT(Employee_ID) and COUNT(Name).'),
  ('SELECT MAX Robot_ID FROM Incidents;', 1, 2, 7, 26, 'Remember MAX is an aggregate function that requires parentheses to enclose its parameter.'),
  ('SELECT r.Status, COUNT Incident_ID AS IncidentCount FROM Robots r JOIN Incidents i ON r.Robot_ID = i.Robot_ID GROUP BY r.Status;', 1, 2, 2, 24, 'Remember COUNT is an aggregate function that requires parentheses to enclose its parameter.'),
  ('SELECT DISTINCT Name, Division, COUNT() FROM Employees;', 1, 5, 1, 24, 'Don''t give up! When using COUNT(),  make sure to specify the things you want to count.'),
  ('SELECT AVG() FROM Logs;', 1, 4, 7, 26, 'AVG() function requires a parameter. Specify column name.'),
  ('SELECT Employee_ID, AVG(SUM(Log_ID)) FROM Logs GROUP BY Employee_ID;', 1, 1, 2, 27, 'Frustration can be a sign of growth. Remember not to nest SUM() inside AVG(). Separate into subquery operations.'),
